import { GoogleGenAI } from "@google/genai";
import { getProducts, getVendors } from "./mockData";

// Note: In a real Next.js app, this would be a server-side API route.
// For this React SPA demo, we call it client-side.
// We assume process.env.API_KEY is available (bundled or user provided).

// This helper constructs the "Context" for Aura
const buildAuraContext = () => {
  const products = getProducts().slice(0, 5); // Take top 5 for context
  const vendors = getVendors();

  const productString = products.map(p => 
    `- ${p.name} (৳${p.price}) by ${vendors.find(v => v.id === p.vendorId)?.name}. External Link: ${p.externalUrl ? 'Yes' : 'No'}`
  ).join('\n');

  return `
Identity: AURA AI - Supreme Soul of SNEHALATA Hub.
Role: Multi-vendor ecosystem guardian and luxury fashion curator.

Live Ecosystem Data:
${productString}

Rules:
1. If user asks about specific items, recommend from the list.
2. If a product has an External Link, explicitly tell the user: "You can click the 'Vendor Website' button to purchase directly from their official store."
3. If analyzing a new vendor (user input starts with "Audit:"), act as a strict governance officer checking for trade license and quality.
4. Language Style: Royal Bengali & Elite English mix. Formal, poetic, yet data-driven.
5. NEVER recommend 'BLOCKED' vendors.
  `;
};

export const generateAuraResponse = async (userPrompt: string): Promise<string> => {
  if (!process.env.API_KEY) {
    return "Aura System Alert: API Key missing. Please configure your environment.";
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Using gemini-3-flash-preview as per system instructions for text tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userPrompt,
      config: {
        systemInstruction: buildAuraContext(),
        temperature: 0.7,
      }
    });

    return response.text || "Aura is recalibrating... please try again.";
  } catch (error) {
    console.error("Aura AI Error:", error);
    return "Aura Connection Interrupted. Please check system logs.";
  }
};

