import React, { useState, useEffect } from 'react';
import { getVendors, getProductsByVendor } from '../services/mockData';
import { Product, Vendor } from '../types';
import { Plus, ShieldCheck, AlertTriangle, Globe, X, Save } from 'lucide-react';
import { ProductCard } from '../components/ProductCard';

export const VendorDashboard: React.FC = () => {
  // Simulating logged-in vendor (ID 1 for demo purposes)
  const [vendor, setVendor] = useState<Vendor | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [isFormOpen, setIsFormOpen] = useState(false);

  // Form State
  const [newProduct, setNewProduct] = useState({
    name: '',
    price: '',
    externalUrl: '',
    category: '',
    description: ''
  });

  useEffect(() => {
    // Simulate fetching current vendor data
    const currentVendor = getVendors().find(v => v.id === 1);
    if (currentVendor) {
      setVendor(currentVendor);
      setProducts(getProductsByVendor(currentVendor.id));
    }
  }, []);

  const handleAddProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!vendor) return;

    const product: Product = {
      id: Date.now(), // Mock ID
      vendorId: vendor.id,
      name: newProduct.name,
      price: Number(newProduct.price),
      externalUrl: newProduct.externalUrl || undefined,
      category: newProduct.category || 'General',
      description: newProduct.description,
      imageUrl: `https://picsum.photos/400/600?random=${Date.now()}`
    };

    setProducts([product, ...products]);
    setIsFormOpen(false);
    setNewProduct({ name: '', price: '', externalUrl: '', category: '', description: '' });
  };

  if (!vendor) return <div className="p-10 text-center text-aura-purple animate-pulse">Initializing Vendor Console...</div>;

  return (
    <div className="min-h-screen bg-black pb-20">
      {/* Header Stats */}
      <div className="bg-aura-darkPurple/20 border-b border-aura-glassBorder relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-purple-600/10 blur-[100px] rounded-full pointer-events-none"></div>
        <div className="max-w-7xl mx-auto px-6 py-10 relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex items-center gap-3 mb-2">
                <h1 className="text-3xl font-serif font-bold text-white">{vendor.name}</h1>
                {vendor.status === 'APPROVED' ? (
                  <span className="bg-green-500/10 text-green-400 border border-green-500/30 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest flex items-center gap-1">
                    <ShieldCheck size={14} /> Aura Verified
                  </span>
                ) : (
                  <span className="bg-red-500/10 text-red-400 border border-red-500/30 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest flex items-center gap-1">
                    <AlertTriangle size={14} /> Review Needed
                  </span>
                )}
              </div>
              <p className="text-gray-400 text-sm max-w-xl">{vendor.description}</p>
            </div>

            <div className="flex gap-4">
               {vendor.websiteUrl && (
                 <a href={vendor.websiteUrl} target="_blank" rel="noreferrer" className="flex items-center gap-2 px-4 py-3 bg-white/5 border border-white/10 rounded-xl hover:bg-white/10 transition-all text-xs font-bold uppercase tracking-widest">
                   <Globe size={16} /> My Website
                 </a>
               )}
               <button 
                onClick={() => setIsFormOpen(!isFormOpen)}
                className="flex items-center gap-2 px-6 py-3 bg-gradient-to-r from-purple-700 to-indigo-700 rounded-xl font-bold uppercase tracking-widest text-xs shadow-lg shadow-purple-900/40 hover:scale-105 transition-transform border border-white/10"
               >
                 {isFormOpen ? <X size={18} /> : <Plus size={18} />}
                 {isFormOpen ? 'Cancel' : 'Add Product'}
               </button>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-6 py-10">

        {/* Add Product Form */}
        {isFormOpen && (
          <div className="mb-12 bg-white/5 border border-white/10 p-8 rounded-3xl animate-in fade-in slide-in-from-top-4 backdrop-blur-sm">
            <h2 className="text-xl font-bold mb-6 border-b border-white/10 pb-4 font-serif">New Inventory Entry</h2>
            <form onSubmit={handleAddProduct} className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] uppercase text-gray-500 font-bold tracking-widest">Product Name</label>
                <input 
                  required
                  value={newProduct.name}
                  onChange={e => setNewProduct({...newProduct, name: e.target.value})}
                  className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors text-sm"
                  placeholder="e.g. Royal Muslin Panjabi"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] uppercase text-gray-500 font-bold tracking-widest">Price (BDT)</label>
                <input 
                  required
                  type="number"
                  value={newProduct.price}
                  onChange={e => setNewProduct({...newProduct, price: e.target.value})}
                  className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors text-sm"
                  placeholder="5000"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] uppercase text-gray-500 font-bold tracking-widest">Category</label>
                <input 
                  required
                  value={newProduct.category}
                  onChange={e => setNewProduct({...newProduct, category: e.target.value})}
                  className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors text-sm"
                  placeholder="e.g. Saree, Panjabi"
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] uppercase text-gray-500 font-bold tracking-widest">External Website Link (Optional)</label>
                <input 
                  type="url"
                  value={newProduct.externalUrl}
                  onChange={e => setNewProduct({...newProduct, externalUrl: e.target.value})}
                  className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors text-sm"
                  placeholder="https://yourstore.com/product"
                />
              </div>
              <div className="md:col-span-2 space-y-2">
                <label className="text-[10px] uppercase text-gray-500 font-bold tracking-widest">Description</label>
                <textarea 
                  required
                  value={newProduct.description}
                  onChange={e => setNewProduct({...newProduct, description: e.target.value})}
                  className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 focus:outline-none focus:border-purple-500 transition-colors h-32 text-sm"
                  placeholder="Describe the material, craft, and heritage..."
                />
              </div>
              <div className="md:col-span-2 flex justify-end">
                <button type="submit" className="flex items-center gap-2 bg-white text-black px-8 py-3 rounded-xl font-bold uppercase tracking-widest hover:bg-gray-200 transition-colors">
                  <Save size={18} /> Publish Item
                </button>
              </div>
            </form>
          </div>
        )}

        {/* Product Grid */}
        <div>
          <h2 className="text-xl font-serif font-bold text-white mb-6 flex items-center gap-4">
            Current Inventory
            <span className="text-xs font-sans font-normal text-gray-500 bg-white/5 px-2 py-1 rounded-md">{products.length} Items</span>
          </h2>

          {products.length === 0 ? (
            <div className="text-center py-20 border border-dashed border-white/10 rounded-3xl text-gray-500">
              No products listed yet. Start your collection by adding a product.
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {products.map(product => (
                <ProductCard key={product.id} product={product} vendor={vendor} />
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateAuraResponse } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product } from '../types';
import { Sparkles, Send, Activity } from 'lucide-react';

export const Home: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "Welcome to the Snehalata Ecosystem. I am Aura. How may I assist your style journey today?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setProducts(getProducts());
    setSalesTicker(getLiveSales());

    // Live Ticker simulation
    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    const auraResponse = await generateAuraResponse(input);

    setIsTyping(false);
    setMessages(prev => [...prev, { role: 'ai', content: auraResponse, timestamp: Date.now() }]);
  };

  return (
    <div className="min-h-screen">
      {/* Hero / Chat Section */}
      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 py-20 overflow-hidden">
        {/* Background Effects */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/10 blur-[120px] rounded-full pointer-events-none" />
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-5 pointer-events-none"></div>

        <div className="relative z-10 w-full max-w-4xl flex flex-col gap-10">

          <div className="text-center space-y-4">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-300">
                   Ecosystem Volume: ৳{salesTicker.toLocaleString()}
                </span>
             </div>
             <h1 className="text-5xl md:text-7xl font-serif font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white/60 leading-tight">
               SNEHALATA
             </h1>
             <p className="text-gray-400 text-sm md:text-base uppercase tracking-widest max-w-lg mx-auto">
               The Direct-to-Vendor Ecosystem powered by Aura Governance
             </p>
          </div>

          {/* AI Chat Interface */}
          <div className="w-full bg-black/40 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl shadow-purple-900/20 flex flex-col h-[400px]">
            <div className="flex-1 p-6 overflow-y-auto space-y-4 scroll-smooth" ref={chatContainerRef}>
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[80%] rounded-2xl p-4 text-sm leading-relaxed ${
                    msg.role === 'user' 
                      ? 'bg-white text-black font-medium' 
                      : 'bg-white/10 text-gray-200 border border-white/5'
                  }`}>
                    {msg.role === 'ai' && <div className="text-[10px] uppercase tracking-widest text-aura-purple mb-1 font-bold">Aura AI</div>}
                    {msg.content}
                  </div>
                </div>
              ))}
              {isTyping && (
                <div className="flex justify-start">
                   <div className="bg-white/5 border border-white/5 rounded-2xl p-4 flex gap-2">
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-75"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-150"></span>
                   </div>
                </div>
              )}
