import { createClient } from '@supabase/supabase-js';

// .env ফাইল থেকে কি (Key) গুলো লোড করা হচ্ছে
const supabaseUrl = (import.meta as any).env.VITE_SUPABASE_URL;
const supabaseAnonKey = (import.meta as any).env.VITE_SUPABASE_ANON_KEY;

export const isSupabaseConfigured = () => {
    return !!supabaseUrl && !!supabaseAnonKey;
}

// যদি কি (Key) না থাকে, তবে নাল (null) রিটার্ন করবে যাতে অ্যাপ ক্র্যাশ না করে
export const supabase = isSupabaseConfigured() 
  ? createClient(supabaseUrl, supabaseAnonKey) 
  : null;

// ভেন্ডর রিকোয়েস্ট সেভ করার ফাংশন
export const submitVendorRequest = async (vendorData: any) => {
    if (!supabase) {
        console.warn("Supabase নট কানেক্টেড। মক ডেটা মোড অন।");
        return { 
            data: { ...vendorData, id: Math.floor(Math.random() * 10000) }, 
            error: null 
        };
    }

    // 'vendors' টেবিলে ডেটা ইনসার্ট করা হচ্ছে
    return await supabase
        .from('vendors')
        .insert([vendorData])
        .select();
};

