import { createClient } from '@supabase/supabase-js';

// VITE_ প্রিফিক্স যুক্ত এনভায়রনমেন্ট ভেরিয়েবলগুলো সরাসরি import.meta.env থেকে নিতে হবে
const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY;

export const isSupabaseConfigured = () => {
    return !!supabaseUrl && !!supabaseAnonKey;
}

// যদি কি (Key) না থাকে, তবে নাল (null) রিটার্ন করবে যাতে অ্যাপ ক্র্যাশ না করে
export const supabase = isSupabaseConfigured() 
  ? createClient(supabaseUrl, supabaseAnonKey) 
  : null;

// ভেন্ডর রিকোয়েস্ট সেভ করার ফাংশন
export const submitVendorRequest = async (vendorData: any) => {
    if (!supabase) {
        console.warn("Supabase নট কানেক্টেড। মক ডেটা মোড অন।");
        // Simulate a delay
        await new Promise(resolve => setTimeout(resolve, 1000));
        return { 
            data: { ...vendorData, id: Math.floor(Math.random() * 10000) }, 
            error: null 
        };
    }

    // 'vendors' টেবিলে ডেটা ইনসার্ট করা হচ্ছে
    return await supabase
        .from('vendors')
        .insert([vendorData])
        .select();
};

import React, { useState } from 'react';
import { auditVendorDescription } from '../services/geminiService';
import { submitVendorRequest } from '../services/supabaseClient';
import { ShieldCheck, AlertTriangle, Loader2, Sparkles, Building2, LogIn } from 'lucide-react';
import { Link } from '../components/Navigation';

export const VendorOnboarding: React.FC = () => {
  const [formData, setFormData] = useState({
    ownerName: '',
    shopName: '',
    description: '',
    contact: ''
  });
  const [status, setStatus] = useState<'IDLE' | 'AUDITING' | 'SAVING' | 'SUCCESS' | 'REJECTED'>('IDLE');
  const [auditResult, setAuditResult] = useState<{ status: string; reason: string } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus('AUDITING');

    // Step 1: Aura AI Audit
    const audit = await auditVendorDescription(formData.shopName, formData.description);
    setAuditResult(audit);

    if (audit.status === 'REJECTED') {
        setStatus('REJECTED');
        return;
    }

    // Step 2: Save to Supabase (or Mock)
    setStatus('SAVING');
    const { error } = await submitVendorRequest({
        name: formData.shopName,
        description: formData.description,
        owner: formData.ownerName,
        contact: formData.contact,
        status: 'APPROVED', // Auto-approved by Aura AI
        joined_at: new Date().toISOString()
    });

    if (error) {
        console.error(error);
        alert("Database connection failed. Please check console.");
        setStatus('IDLE');
    } else {
        setStatus('SUCCESS');
    }
  };

  return (
    <div className="min-h-screen bg-black flex items-center justify-center p-6 relative overflow-hidden">
        {/* Background Animation */}
        <div className="absolute top-0 left-0 w-full h-full bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10 pointer-events-none"></div>
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-purple-900/20 blur-[100px] rounded-full"></div>

        <div className="relative z-10 w-full max-w-2xl">
            {/* Back to Home */}
            <Link to="/" className="inline-block mb-6 text-gray-400 hover:text-white transition-colors text-sm font-bold uppercase tracking-widest">
                ← নীড়ে ফিরে যান
            </Link>

            <div className="bg-aura-glass backdrop-blur-xl border border-aura-glassBorder rounded-3xl p-10 shadow-2xl">

                <div className="text-center mb-10">
                    <Sparkles className="mx-auto text-aura-purple mb-4" size={40} />
                    <h1 className="text-3xl font-serif font-bold text-white mb-2">Aura Ecosystem পার্টনারশিপ</h1>
                    <p className="text-gray-400">আপনার ব্র্যান্ড রেজিস্ট্রেশন করুন। Aura AI আপনার আবেদন যাচাই করবে।</p>
                </div>

                {status === 'SUCCESS' ? (
                    <div className="text-center animate-in zoom-in duration-500">
                        <div className="w-20 h-20 bg-green-500/20 rounded-full flex items-center justify-center mx-auto mb-6">
                            <ShieldCheck size={40} className="text-green-400" />
                        </div>
                        <h2 className="text-2xl font-bold text-white mb-4">স্বাগতম, পার্টনার!</h2>
                        <p className="text-gray-300 mb-6">{auditResult?.reason}</p>
                        <div className="flex justify-center gap-4">
                            <Link to="/dashboard" className="inline-block bg-white text-black px-8 py-3 rounded-xl font-bold uppercase tracking-widest hover:bg-gray-200 transition-colors">
                                ড্যাশবোর্ডে যান
                            </Link>
                        </div>
                    </div>
                ) : status === 'REJECTED' ? (
                    <div className="text-center animate-in shake duration-500">
                        <div className="w-20 h-20 bg-red-500/20 rounded-full flex items-center justify-center mx-auto mb-6">
                            <AlertTriangle size={40} className="text-red-400" />
                        </div>
                        <h2 className="text-2xl font-bold text-red-400 mb-4">আবেদন বাতিল করা হয়েছে</h2>
                        <p className="text-gray-300 mb-6 bg-red-500/10 p-4 rounded-xl border border-red-500/20">{auditResult?.reason}</p>
                        <button onClick={() => setStatus('IDLE')} className="text-white underline hover:text-aura-purple">
                            আবার চেষ্টা করুন
                        </button>
                    </div>
                ) : (
                    <>
                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-2">
                                    <label className="text-xs font-bold uppercase tracking-widest text-gray-500">মালিকের নাম</label>
                                    <input 
                                        required
                                        value={formData.ownerName}
                                        onChange={e => setFormData({...formData, ownerName: e.target.value})}
                                        className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 text-white focus:border-aura-purple focus:outline-none"
                                        placeholder="আপনার নাম"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <label className="text-xs font-bold uppercase tracking-widest text-gray-500">যোগাযোগ</label>
                                    <input 
                                        required
                                        value={formData.contact}
                                        onChange={e => setFormData({...formData, contact: e.target.value})}
                                        className="w-full bg-black/50 border border-white/20 rounded-xl px-4 py-3 text-white focus:border-aura-purple focus:outline-none"
                                        placeholder="017..."
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs font-bold uppercase tracking-widest text-gray-500">ব্র্যান্ড / শপের নাম</label>
                                <div className="relative">
                                    <Building2 className="absolute left-4 top-3.5 text-gray-500" size={18} />
                                    <input 
                                        required
                                        value={formData.shopName}
                                        onChange={e => setFormData({...formData, shopName: e.target.value})}
                                        className="w-full bg-black/50 border border-white/20 rounded-xl pl-12 pr-4 py-3 text-white focus:border-aura-purple focus:outline-none"
                                        placeholder="e.g. Dhaka Weavers"
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs font-bold uppercase tracking-widest text-gray-500">ব্র্যান্ডের বিবরণ (Aura Audit)</label>
                                <textarea 
                                    required
                                    value={formData.description}
                                    onChange={e => setFormData({...formData, description: e.target.value})}
                                    className="w-full h-32 bg-black/50 border border-white/20 rounded-xl px-4 py-3 text-white focus:border-aura-purple focus:outline-none"
                                    placeholder="আমরা কী বিক্রি করি? আমাদের বিশেষত্ব কী? (e.g., Authentic Jamdani Saree directly from weavers...)"
                                />
                                <p className="text-[10px] text-gray-500">* Aura AI এই বিবরণ যাচাই করে দেখবে এটি ইকোসিস্টেমের সাথে মানানসই কিনা।</p>
                            </div>

                            <button 
                                type="submit" 
                                disabled={status !== 'IDLE'}
                                className="w-full bg-gradient-to-r from-aura-purple to-indigo-700 text-white font-bold uppercase tracking-widest py-4 rounded-xl hover:scale-[1.02] transition-transform shadow-lg shadow-purple-900/40 flex items-center justify-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                {status === 'AUDITING' ? (
                                    <>
                                        <Loader2 className="animate-spin" /> Aura যাচাই করছে...
                                    </>
                                ) : status === 'SAVING' ? (
                                    <>
                                        <Loader2 className="animate-spin" /> ডেটাবেসে সেভ হচ্ছে...
                                    </>
                                ) : (
                                    <>
                                        রেজিস্ট্রেশন সম্পন্ন করুন
                                    </>
                                )}
                            </button>
                        </form>

                        {/* Login Link */}
                        <div className="mt-8 pt-6 border-t border-white/10 text-center">
                            <p className="text-gray-400 text-sm mb-4">আগেই অ্যাকাউন্ট আছে?</p>
                            <Link to="/dashboard" className="inline-flex items-center gap-2 text-aura-purple font-bold hover:text-white transition-colors">
                                <LogIn size={18} /> ভেন্ডর লগইন
                            </Link>
                        </div>
                    </>
                )}
            </div>
        </div>
    </div>
  );
};

