// --- AURA VENDOR AUDIT (SMART ONBOARDING) ---
export const auditVendorDescription = async (shopName: string, description: string): Promise<{ status: 'APPROVED' | 'REJECTED' | 'PENDING'; reason: string }> => {
    if (!process.env.API_KEY) {
        return { status: 'APPROVED', reason: 'System in Developer Mode (Auto-Approved)' };
    }

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        You are Aura Governance AI. You approve or reject vendors for the "Snehalata Ecosystem".

        Criteria for APPROVAL:
        1. Must sell authentic Bangladeshi clothing (Jamdani, Muslin, Khadi, etc.) OR high-quality modern fashion (Streetwear, Fusion).
        2. Must sound professional and ethical.
        3. NO illegal items, drugs, or cheap knock-offs.

        Vendor Name: ${shopName}
        Description: ${description}

        Respond ONLY in JSON format:
        { "status": "APPROVED" or "REJECTED", "reason": "Short explanation in Bengali/English mix" }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        const result = JSON.parse(response.text || '{}');
        return {
            status: result.status || 'PENDING',
            reason: result.reason || 'Manual review required.'
        };
    } catch (error) {
        console.error("Audit Error:", error);
        return { status: 'PENDING', reason: 'AI Audit Server Offline. Marked for manual review.' };
    }
};

// --- SEARCH INTENT ANALYSIS ---
export const analyzeSearchIntent = async (userPrompt: string): Promise<{
    category: string | null;
    maxPrice: number | null;
    minPrice: number | null;
    vendorName: string | null;
    keywords: string[];
    isSearchQuery: boolean;
} | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        Act as a search engine parser for 'Snehalata', a Bangladeshi fashion ecosystem.

        Analyze the user's input: "${userPrompt}"

        Extract search filters if the user is looking for products.

        Output JSON schema:
        {
            "category": string | null, // e.g., "Saree", "Panjabi", "Hoodie"
            "maxPrice": number | null,
            "minPrice": number | null,
            "vendorName": string | null, // e.g., "Royal Bengal", "Urban Dhaka"
            "keywords": string[],
            "isSearchQuery": boolean // true if user wants to see products, false if just greetings/questions. If user says "Show all" or "Reset", set this to true with null filters.
        }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        const text = response.text;
        if (!text) return null;
        return JSON.parse(text);
    } catch (error) {
        console.error("Search Intent Error:", error);
        return null;
    }
};

