    e.preventDefault();
    if (!input.trim()) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    // Parallel execution for response and search intent
    const [auraResponse, intent] = await Promise.all([
        generateAuraResponse(input),
        analyzeSearchIntent(input)
    ]);

    setIsTyping(false);
    setMessages(prev => [...prev, { role: 'ai', content: auraResponse, timestamp: Date.now() }]);

    // Apply filters based on intent
    if (intent && intent.isSearchQuery) {
        let filtered = [...allProducts];
        let hasFilter = false;

        if (intent.category) {
            filtered = filtered.filter(p => 
                p.category.toLowerCase().includes(intent.category!.toLowerCase()) || 
                p.name.toLowerCase().includes(intent.category!.toLowerCase())
            );
            hasFilter = true;
