        if (intent.maxPrice) {
            filtered = filtered.filter(p => p.price <= intent.maxPrice!);
            hasFilter = true;
        }
        if (intent.minPrice) {
            filtered = filtered.filter(p => p.price >= intent.minPrice!);
            hasFilter = true;
        }
        if (intent.vendorName) {
