      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: cleanUserImage, mimeType: 'image/jpeg' } },
            { text: "Overlay the clothing item from the second image onto the person in the first image. Make it look realistic." },
             // Note: In a real scenario, we would send the product image as a second part or train the model. 
             // Currently sending just user image + prompt for demo as we might not have product base64 ready.
          ],
        },
      });
