// --- AURA VENDOR AUDIT (SMART ONBOARDING) ---
export const auditVendorDescription = async (shopName: string, description: string): Promise<{ status: 'APPROVED' | 'REJECTED' | 'PENDING'; reason: string }> => {
    if (!process.env.API_KEY) {
        return { status: 'APPROVED', reason: 'System in Developer Mode (Auto-Approved)' };
    }

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        You are Aura Governance AI. You approve or reject vendors for the "Snehalata Ecosystem".

        Criteria for APPROVAL:
        1. Must sell authentic Bangladeshi clothing (Jamdani, Muslin, Khadi, etc.) OR high-quality modern fashion (Streetwear, Fusion).
        2. Must sound professional and ethical.
        3. NO illegal items, drugs, or cheap knock-offs.

        Vendor Name: ${shopName}
        Description: ${description}

        Respond ONLY in JSON format:
        { "status": "APPROVED" or "REJECTED", "reason": "Short explanation in Bengali/English mix" }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        const result = JSON.parse(response.text || '{}');
        return {
            status: result.status || 'PENDING',
            reason: result.reason || 'Manual review required.'
        };
    } catch (error) {
        console.error("Audit Error:", error);
        return { status: 'PENDING', reason: 'AI Audit Server Offline. Marked for manual review.' };
    }
};

// --- SEARCH INTENT ANALYSIS ---
export const analyzeSearchIntent = async (userPrompt: string): Promise<{
    category: string | null;
    maxPrice: number | null;
    minPrice: number | null;
    vendorName: string | null;
    keywords: string[];
    isSearchQuery: boolean;
} | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        Act as a search engine parser for 'Snehalata', a Bangladeshi fashion ecosystem.

        Analyze the user's input: "${userPrompt}"

        Extract search filters if the user is looking for products.

        Output JSON schema:
        {
            "category": string | null, // e.g., "Saree", "Panjabi", "Hoodie"
            "maxPrice": number | null,
            "minPrice": number | null,
            "vendorName": string | null, // e.g., "Royal Bengal", "Urban Dhaka"
            "keywords": string[],
            "isSearchQuery": boolean // true if user wants to see products, false if just greetings/questions. If user says "Show all" or "Reset", set this to true with null filters.
        }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        const text = response.text;
        if (!text) return null;
        return JSON.parse(text);
    } catch (error) {
        console.error("Search Intent Error:", error);
        return null;
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { generateAuraResponse, analyzeSearchIntent } from '../services/geminiService';
import { getProducts, getVendors, getLiveSales } from '../services/mockData';
import { ProductCard } from '../components/ProductCard';
import { ChatMessage, Product, Vendor } from '../types';
import { Sparkles, Send, Activity, Users, ShieldCheck, Filter, X, Trash2, Clock } from 'lucide-react';
import { Link } from '../components/Navigation';

export const Home: React.FC = () => {
  const [allProducts, setAllProducts] = useState<Product[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [salesTicker, setSalesTicker] = useState(0);
  const [isFiltered, setIsFiltered] = useState(false);

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'ai', content: "Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const chatContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    // Live Ticker simulation
    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    // Parallel execution for response and search intent
    const [auraResponse, intent] = await Promise.all([
        generateAuraResponse(input),
        analyzeSearchIntent(input)
    ]);

    setIsTyping(false);
    setMessages(prev => [...prev, { role: 'ai', content: auraResponse, timestamp: Date.now() }]);

    // Apply filters based on intent
    if (intent && intent.isSearchQuery) {
        let filtered = [...allProducts];
        let hasFilter = false;

        if (intent.category) {
            filtered = filtered.filter(p => 
                p.category.toLowerCase().includes(intent.category!.toLowerCase()) || 
                p.name.toLowerCase().includes(intent.category!.toLowerCase())
            );
            hasFilter = true;
        }
        if (intent.maxPrice) {
            filtered = filtered.filter(p => p.price <= intent.maxPrice!);
            hasFilter = true;
        }
        if (intent.minPrice) {
            filtered = filtered.filter(p => p.price >= intent.minPrice!);
            hasFilter = true;
        }
        if (intent.vendorName) {
            const matchingVendors = vendors.filter(v => v.name.toLowerCase().includes(intent.vendorName!.toLowerCase()));
            const vendorIds = matchingVendors.map(v => v.id);
            if (vendorIds.length > 0) {
                 filtered = filtered.filter(p => vendorIds.includes(p.vendorId));
                 hasFilter = true;
            }
        }

        // Expanded Keyword Filtering (Colors, Materials, Styles)
        if (intent.keywords && intent.keywords.length > 0) {
            filtered = filtered.filter(p => {
                const productText = `${p.name} ${p.description} ${p.category}`.toLowerCase();
                // Check if all keywords are present in product text
                return intent.keywords.every((keyword: string) => productText.includes(keyword.toLowerCase()));
            });
            if (intent.keywords.length > 0) {
                hasFilter = true;
            }
        }

        setProducts(filtered);
        setIsFiltered(hasFilter);

        // Auto-scroll to products if search was successful and we have results
        if (hasFilter && filtered.length > 0) {
             const productSection = document.getElementById('product-section');
             productSection?.scrollIntoView({ behavior: 'smooth' });
        }
    }
  };

  const clearFilters = () => {
      setProducts(allProducts);
      setIsFiltered(false);
  };

  const clearChat = () => {
    setMessages([
        { role: 'ai', content: "Snehalata-স্নেহলতা ইকোসিস্টেমে স্বাগতম। আমি Aura। আজ আপনার স্টাইল যাত্রায় কীভাবে সাহায্য করতে পারি?", timestamp: Date.now() }
    ]);
  };

  const formatTime = (timestamp: number) => {
    return new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <div className="min-h-screen">
      {/* Hero / Chat Section */}
      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 py-20 overflow-hidden">
        {/* Background Effects */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/10 blur-[120px] rounded-full pointer-events-none" />
        <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-5 pointer-events-none"></div>

        <div className="relative z-10 w-full max-w-4xl flex flex-col gap-10">

          <div className="text-center space-y-4">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-300">
                   Ecosystem ভলিউম: ৳{salesTicker.toLocaleString()}
                </span>
             </div>
             <h1 className="text-4xl md:text-6xl font-serif font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white/60 leading-tight">
               SNEHALATA-স্নেহলতা
             </h1>
             <p className="text-gray-400 text-sm md:text-base uppercase tracking-widest max-w-lg mx-auto">
               Direct-to-Vendor ইকোসিস্টেম - Aura Governance দ্বারা পরিচালিত
             </p>
          </div>

          {/* AI Chat Interface */}
          <div className="w-full bg-black/40 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl shadow-purple-900/20 flex flex-col h-[400px]">
            {/* Chat Header */}
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5 backdrop-blur-md sticky top-0 z-10">
                <div className="flex items-center gap-2">
                    <Sparkles size={16} className="text-aura-purple" />
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Aura Live Chat</span>
                </div>
                <button 
                    onClick={clearChat} 
                    className="text-gray-500 hover:text-red-400 transition-colors p-1 rounded-full hover:bg-white/5" 
                    title="Clear Chat"
                >
                    <Trash2 size={16} />
                </button>
            </div>

            <div className="flex-1 p-6 overflow-y-auto space-y-4 scroll-smooth" ref={chatContainerRef}>
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[80%] rounded-2xl p-4 text-sm leading-relaxed ${
                    msg.role === 'user' 
                      ? 'bg-white text-black font-medium' 
                      : 'bg-white/10 text-gray-200 border border-white/5'
                  }`}>
                    {msg.role === 'ai' && <div className="text-[10px] uppercase tracking-widest text-aura-purple mb-1 font-bold">Aura AI</div>}
                    <div className="whitespace-pre-wrap">{msg.content}</div>

                    {/* Message Timestamp */}
                    <div className={`mt-2 text-[10px] flex items-center justify-end gap-1 ${msg.role === 'user' ? 'text-gray-400' : 'text-gray-500'}`}>
                        {formatTime(msg.timestamp)}
                        {msg.role === 'ai' && <Clock size={10} />}
                    </div>
                  </div>
                </div>
              ))}

              {isTyping && (
                <div className="flex justify-start">
                   <div className="bg-white/5 border border-white/5 rounded-2xl p-4 flex gap-2">
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-75"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-150"></span>
                   </div>
                </div>
