import React, { useState, useEffect } from 'react';
import { useParams, Link } from '../components/Navigation';
import { getProducts } from '../services/mockData';
import { Product } from '../types';
import { ArrowLeft, Upload, Sparkles, RefreshCcw, Camera, Shirt, X } from 'lucide-react';
import { generateTryOnTransformation } from '../services/geminiService';

export const VirtualTryOn: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [product, setProduct] = useState<Product | undefined>(undefined);
  const [userImage, setUserImage] = useState<string | null>(null);
  const [productImage, setProductImage] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (id) {
      const found = getProducts().find(p => p.id === Number(id));
      setProduct(found);
      if (found) {
        setProductImage(found.imageUrl);
      }
    }
  }, [id]);

  const convertUrlToBase64 = async (url: string): Promise<string> => {
    const response = await fetch(url);
    const blob = await response.blob();
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.onerror = reject;
        reader.readAsDataURL(blob);
    });
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUserImage(reader.result as string);
        setGeneratedImage(null);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleProductImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setProductImage(reader.result as string);
        setProduct(undefined); // Clear linked product since user uploaded custom
        setGeneratedImage(null);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const clearProduct = () => {
    setProductImage(null);
    setProduct(undefined);
    setGeneratedImage(null);
  };

  const handleGenerate = async () => {
    if (!userImage || !productImage) return;
    setIsProcessing(true);
    setError(null);

    try {
        let productBase64 = "";

        // If it's a data URL (uploaded by user), use it directly
        if (productImage.startsWith('data:')) {
            productBase64 = productImage;
        } else {
            // It's a URL (from existing product)
            try {
                productBase64 = await convertUrlToBase64(productImage);
            } catch (e) {
                console.warn("Could not fetch product image for base64 (CORS?).");
                setError("Product image access restricted (CORS). Please upload the product image manually.");
                setIsProcessing(false);
                return;
            }
        }

        const result = await generateTryOnTransformation(userImage, productBase64);

        if (result) {
            setGeneratedImage(result);
        } else {
            setError("AI transformation failed. Please try a clearer photo.");
        }
    } catch (err) {
        setError("An error occurred during processing.");
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen bg-black pb-20">
       <div className="max-w-7xl mx-auto px-6 py-10">
          <Link to="/" className="inline-flex items-center gap-2 text-gray-400 hover:text-white mb-8 transition-colors">
             <ArrowLeft size={16} /> Back to Hub
          </Link>

          <h1 className="text-4xl font-serif font-bold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-white mb-2">
            AI Virtual Try-On
          </h1>
          <p className="text-gray-400 mb-10 max-w-xl">
            Upload your photo and a clothing item to see how it fits. Powered by Aura Vision (Gemini 2.5).
          </p>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10">

            {/* Input Section */}
            <div className="space-y-6">
                {/* User Photo Upload */}
                <div className="bg-white/5 border border-white/10 rounded-3xl p-6 relative group hover:border-aura-purple/50 transition-colors h-[350px] flex flex-col items-center justify-center border-dashed">
                    {userImage ? (
                        <div className="relative w-full h-full rounded-2xl overflow-hidden">
                            <img src={userImage} alt="You" className="w-full h-full object-cover" />
                            <button 
                                onClick={() => setUserImage(null)}
                                className="absolute top-2 right-2 bg-black/60 p-2 rounded-full text-white hover:bg-red-500 transition-colors z-10"
                                title="Remove photo"
                            >
                                <RefreshCcw size={16} />
                            </button>
                            <div className="absolute bottom-2 left-2 bg-black/60 px-3 py-1 rounded-full text-xs font-bold text-white">Your Photo</div>
                        </div>
                    ) : (
                        <label className="cursor-pointer flex flex-col items-center gap-4 text-center w-full h-full justify-center">
                            <div className="w-16 h-16 bg-white/10 rounded-full flex items-center justify-center group-hover:bg-aura-purple/20 transition-colors">
                                <Camera size={32} className="text-aura-purple" />
                            </div>
                            <div>
                                <h3 className="text-lg font-bold text-white">Upload Your Photo</h3>
                                <p className="text-sm text-gray-500 mt-1">Full body or half body shots work best</p>
                            </div>
                            <input type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
                        </label>
                    )}
                </div>

                {/* Product Image Upload / Selection */}
                <div className="bg-white/5 border border-white/10 rounded-3xl p-6 relative group hover:border-aura-purple/50 transition-colors flex flex-col items-center justify-center border-dashed min-h-[150px]">
                    {productImage ? (
                        <div className="flex items-center gap-4 w-full">
                             <div className="relative w-24 h-24 shrink-0 rounded-xl overflow-hidden border border-white/10">
                                <img src={productImage} alt="Product" className="w-full h-full object-cover" />
                                <button 
                                    onClick={clearProduct}
                                    className="absolute top-1 right-1 bg-black/60 p-1 rounded-full text-white hover:bg-red-500 transition-colors"
                                    title="Remove item"
                                >
                                    <X size={12} />
                                </button>
                             </div>
                             <div className="flex-1 min-w-0">
                                 {product && productImage === product.imageUrl ? (
                                    <>
                                        <h4 className="font-bold text-white text-sm truncate">{product.name}</h4>
                                        <p className="text-gray-400 text-xs">৳{product.price.toLocaleString()}</p>
                                    </>
                                 ) : (
                                    <>
                                        <h4 className="font-bold text-white text-sm">Custom Upload</h4>
                                        <p className="text-gray-400 text-xs">User uploaded item</p>
                                    </>
                                 )}

                                 <label className="mt-3 inline-flex items-center gap-2 text-xs font-bold uppercase tracking-widest text-aura-purple hover:text-white cursor-pointer transition-colors bg-white/5 px-3 py-2 rounded-lg border border-white/10 hover:border-white/30">
                                    <Upload size={12} /> Replace Item
                                    <input type="file" accept="image/*" onChange={handleProductImageUpload} className="hidden" />
                                 </label>
                             </div>
                        </div>
                    ) : (
                        <label className="cursor-pointer flex items-center gap-4 text-center w-full justify-center p-2">
                            <div className="w-12 h-12 bg-white/10 rounded-full flex items-center justify-center group-hover:bg-aura-purple/20 transition-colors">
                                <Shirt size={24} className="text-gray-300 group-hover:text-aura-purple" />
                            </div>
                            <div className="text-left">
                                <h3 className="text-sm font-bold text-white">Upload Clothing Item</h3>
                                <p className="text-xs text-gray-500">Select any image from your device</p>
                            </div>
                            <input type="file" accept="image/*" onChange={handleProductImageUpload} className="hidden" />
                        </label>
                    )}
                </div>

                <button 
                    onClick={handleGenerate}
                    disabled={!userImage || !productImage || isProcessing}
                    className={`w-full py-4 rounded-xl font-bold uppercase tracking-widest text-sm flex items-center justify-center gap-2 transition-all ${
                        !userImage || !productImage || isProcessing 
                        ? 'bg-white/10 text-gray-500 cursor-not-allowed' 
                        : 'bg-gradient-to-r from-aura-purple to-indigo-600 hover:scale-[1.02] text-white shadow-lg shadow-purple-900/40'
                    }`}
                >
                    {isProcessing ? (
                        <>
                           <span className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin" />
                           Processing AI...
                        </>
                    ) : (
                        <>
                           <Sparkles size={18} /> Generate Preview
                        </>
                    )}
                </button>
                {error && <p className="text-red-400 text-sm text-center bg-red-500/10 p-2 rounded-lg border border-red-500/20">{error}</p>}
            </div>

            {/* Output Section */}
            <div className="bg-aura-glass border border-aura-glassBorder rounded-3xl p-1 relative overflow-hidden h-[600px] flex items-center justify-center">
                 {generatedImage ? (
                     <img src={generatedImage} alt="Generated Try-On" className="w-full h-full object-cover rounded-2xl animate-in fade-in duration-700" />
                 ) : (
                     <div className="text-center space-y-4 opacity-30">
                         <Sparkles size={64} className="mx-auto" />
                         <p className="font-serif text-2xl uppercase tracking-widest">Aura Vision</p>
                         <p className="text-sm">AI Magic will appear here</p>
                     </div>
                 )}

                 {/* Decorative background elements */}
                 <div className="absolute inset-0 bg-gradient-to-t from-aura-purple/10 to-transparent pointer-events-none" />
            </div>

          </div>
       </div>
    </div>
  );
};

