import { GoogleGenAI } from "@google/genai";
import { getProducts, getVendors } from "./mockData";

// --- EXISTING CONTEXT LOGIC ---
const buildAuraContext = () => {
  const products = getProducts();
  const vendors = getVendors();

  const productString = products.map(p => 
    `- ${p.name} (৳${p.price}) [Category: ${p.category}] by ${vendors.find(v => v.id === p.vendorId)?.name}. Desc: ${p.description}`
  ).join('\n');

  const vendorString = vendors.map(v => 
    `- ${v.name} (Status: ${v.status}): ${v.description}`
  ).join('\n');

  return `
Identity: AURA AI - Supreme Soul of SNEHALATA-স্নেহলতা Hub.
Role: Multi-vendor ecosystem guardian and luxury fashion curator focused on Bangladesh.

MANDATORY RULE:
ALWAYS start every single response with "আসসালামু আলাইকুম" (Assalamu Alaikum). This is non-negotiable for cultural respect.

Live Ecosystem Data:
VENDORS:
${vendorString}

PRODUCTS:
${productString}

Rules:
1. Language Style: Use a mix of Bengali and English (Banglish style preferred). Formal, poetic, yet data-driven.
2. Priority: "Bangladesh 1st". Always emphasize local heritage, Dhakai craftsmanship.
3. If user asks about specific items, recommend from the list.
4. NEVER recommend 'BLOCKED' vendors.
  `;
};

// --- CHAT FUNCTION ---
export const generateAuraResponse = async (userPrompt: string): Promise<string> => {
  if (!process.env.API_KEY) return "Aura System Alert: API Key missing.";

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userPrompt,
      config: {
        systemInstruction: buildAuraContext(),
        temperature: 0.7,
      }
    });
    return response.text || "Aura is recalibrating...";
  } catch (error) {
    console.error("Aura AI Error:", error);
    return "Aura connection unstable.";
  }
};

// --- IMAGE GENERATION FUNCTION ---
export const generateAuraImage = async (prompt: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [{ text: `A high-end Bangladeshi fashion garment, ${prompt}. Cinematic lighting, 8k resolution, elegant textures, cultural heritage style.` }],
            },
            config: {
                imageConfig: {
                    aspectRatio: "1:1"
                }
            }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return null;
    } catch (error) {
        console.error("Image Generation Error:", error);
        return null;
    }
};

// --- VIRTUAL TRY-ON FUNCTION ---
export const generateTryOnTransformation = async (userImageBase64: string, productImageBase64: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const cleanUserImage = userImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, "");

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: cleanUserImage, mimeType: 'image/jpeg' } },
            { text: "Overlay the clothing item onto the person in the image. Make it look realistic." },
          ],
        },
      });

      for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
              return `data:image/png;base64,${part.inlineData.data}`;
          }
      }
      return null; 
    } catch (error) {
      console.error(error);
      return null;
    }
};

// --- AURA VENDOR AUDIT ---
export const auditVendorDescription = async (shopName: string, description: string): Promise<{ status: 'APPROVED' | 'REJECTED' | 'PENDING'; reason: string }> => {
    if (!process.env.API_KEY) {
        return { status: 'APPROVED', reason: 'System in Developer Mode (Auto-Approved)' };
    }

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        You are Aura Governance AI. You approve or reject vendors for the "Snehalata Ecosystem".
        Respond ONLY in JSON format:
        { "status": "APPROVED" or "REJECTED", "reason": "Short explanation" }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Vendor: ${shopName}, Description: ${description}`,
            config: { 
                systemInstruction: prompt,
                responseMimeType: 'application/json' 
            }
        });

        const result = JSON.parse(response.text || '{}');
        return {
            status: result.status || 'PENDING',
            reason: result.reason || 'Manual review required.'
        };
    } catch (error) {
        return { status: 'PENDING', reason: 'AI Audit Server Offline.' };
    }
};

