export interface SearchIntent {
    category: string | null;
    maxPrice: number | null;
    minPrice: number | null;
    vendorName: string | null;
    color: string | null;
    material: string | null;
    style: string | null;
    keywords: string[];
    isSearchQuery: boolean;
    shouldGenerateImage: boolean;
    imagePrompt: string | null;
}

export const analyzeSearchIntent = async (userPrompt: string): Promise<SearchIntent | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        Act as a search engine parser for 'Snehalata' ecosystem.
        Analyze: "${userPrompt}"

        Extract: category, maxPrice, minPrice, vendorName, color, material, style, keywords.
        isSearchQuery: true if user is looking for products.
        shouldGenerateImage: true if user mentions a color, style, or explicitly asks for an image/preview.
        imagePrompt: A descriptive prompt for an image generator (e.g. "A red jamdani saree").

        Output JSON:
        {
            "category": string | null,
            "maxPrice": number | null,
            "minPrice": number | null,
            "vendorName": string | null,
            "color": string | null,
            "material": string | null,
            "style": string | null,
            "keywords": string[],
            "isSearchQuery": boolean,
            "shouldGenerateImage": boolean,
            "imagePrompt": string | null
        }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        return JSON.parse(response.text || '{}');
    } catch (error) {
        console.error("Search Intent Error:", error);
        return null;
    }
};

