        setIsGeneratingImage(true);
        generatedImageUrl = await generateAuraImage(intent.imagePrompt) || undefined;
        setIsGeneratingImage(false);
    }

    setMessages(prev => [...prev, { 
        role: 'ai', 
        content: auraResponse, 
        timestamp: Date.now(),
        generatedImageUrl 
    }]);

    // Apply advanced filters based on intent
