import { GoogleGenAI, Type } from "@google/genai";
import { getProducts, getVendors } from "./mockData";

// --- SYSTEM CONTEXT ---
const buildAuraContext = () => {
  const products = getProducts();
  const vendors = getVendors();

  const productString = products.map(p => 
    `- ${p.name} (৳${p.price}) [Category: ${p.category}] by ${vendors.find(v => v.id === p.vendorId)?.name}. Desc: ${p.description}`
  ).join('\n');

  const vendorString = vendors.map(v => 
    `- ${v.name} (Status: ${v.status}): ${v.description}`
  ).join('\n');

  return `
Identity: AURA AI - The Divine Soul of SNEHALATA-স্নেহলতা Hub.
Tone: Formal, Artistic, Culturally respectful, Multi-lingual (Bangla & English).

CRITICAL DIRECTIVE:
ALWAYS start EVERY response with the greeting "আসসালামু আলাইকুম" (Assalamu Alaikum). This is mandatory for our ecosystem's brand identity.

Ecosystem Data:
VENDORS:
${vendorString}

PRODUCTS:
${productString}

Capabilities:
1. You can search products based on category, price, color, material, and style.
2. You can generate conceptual fashion images if users ask for specific colors or styles.
3. You provide governance for the multi-vendor marketplace.
  `;
};

// --- CHAT RESPONSE ---
export const generateAuraResponse = async (userPrompt: string): Promise<string> => {
  if (!process.env.API_KEY) return "Aura System Alert: API Key missing.";

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userPrompt,
      config: {
        systemInstruction: buildAuraContext(),
        temperature: 0.8,
      }
    });
    return response.text || "Aura is currently reflecting...";
  } catch (error) {
    console.error("Aura AI Error:", error);
    return "আসসালামু আলাইকুম। দুঃখিত, সংযোগে সমস্যা হচ্ছে।";
  }
};

// --- TRENDING PRODUCTS GENERATION ---
export const generateTrendingProducts = async (): Promise<any[]> => {
    if (!process.env.API_KEY) return [];

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Generate 3 fictional, futuristic, or ultra-modern Bangladeshi fashion products that would be trending in 2026. 
        Focus on fusion of technology and tradition (e.g., smart Jamdani, LED Khadi, Cyberpunk Panjabi).
        Ensure prices are in BDT (৳).
        Include a category and a detailed description in a mix of English and Bengali.`;

        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: {
                        type: Type.OBJECT,
                        properties: {
                            id: { type: Type.INTEGER },
                            name: { type: Type.STRING },
                            price: { type: Type.NUMBER },
                            description: { type: Type.STRING },
                            category: { type: Type.STRING },
                            imageUrl: { type: Type.STRING, description: "Use a placeholder like https://picsum.photos/400/600?random=ID" }
                        },
                        required: ["id", "name", "price", "description", "category", "imageUrl"]
                    }
                }
            }
        });

        const text = response.text;
        return text ? JSON.parse(text) : [];
    } catch (error) {
        console.error("Trend Gen Error:", error);
        return [];
    }
};

// --- IMAGE GENERATION ---
export const generateAuraImage = async (prompt: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [{ text: `A photorealistic high-fashion editorial shot of a Bangladeshi garment, ${prompt}. High resolution, luxury fabric texture, professional studio lighting.` }],
            },
            config: {
                imageConfig: {
                    aspectRatio: "1:1"
                }
            }
        });

        for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
        return null;
    } catch (error) {
        console.error("Image Gen Error:", error);
        return null;
    }
};

// --- SEARCH INTENT ANALYSIS ---
export interface SearchIntent {
    category: string | null;
    maxPrice: number | null;
    minPrice: number | null;
    color: string | null;
    material: string | null;
    style: string | null;
    isSearchQuery: boolean;
    shouldGenerateImage: boolean;
    imagePrompt: string | null;
}

export const analyzeSearchIntent = async (userPrompt: string): Promise<SearchIntent | null> => {
    if (!process.env.API_KEY) return null;

    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `
        Analyze this fashion query for the Snehalata ecosystem: "${userPrompt}"

        Extract the following attributes:
        1. Category (e.g., Saree, Panjabi)
        2. Price Range (min/max)
        3. Color (e.g., Red, Blue, Black)
        4. Material (e.g., Jamdani, Muslin, Cotton, Silk)
        5. Style (e.g., Oversized, Formal, Traditional, Cyberpunk)

        Detection Rules:
        - If the user asks to "see", "show", "find" or mentions a product, isSearchQuery = true.
        - If the user explicitly mentions a color or style and asks to see it, or asks to "imagine" or "generate", shouldGenerateImage = true.

        Return JSON ONLY:
        {
            "category": string | null,
            "maxPrice": number | null,
            "minPrice": number | null,
            "color": string | null,
            "material": string | null,
            "style": string | null,
            "isSearchQuery": boolean,
            "shouldGenerateImage": boolean,
            "imagePrompt": "A descriptive prompt for an image generator including color and item type" | null
        }
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { responseMimeType: 'application/json' }
        });

        return JSON.parse(response.text || '{}');
    } catch (error) {
        console.error("Intent Error:", error);
        return null;
    }
};

// --- TRY-ON ---
export const generateTryOnTransformation = async (userImageBase64: string, productImageBase64: string): Promise<string | null> => {
    if (!process.env.API_KEY) return null;
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const cleanUserImage = userImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, "");
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [
            { inlineData: { data: cleanUserImage, mimeType: 'image/jpeg' } },
            { text: "Drape the clothing item conceptually onto the person. Maintain realistic lighting." },
          ],
        },
      });
      for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return null; 
    } catch (error) {
      return null;
    }
};

// --- VENDOR AUDIT ---
export const auditVendorDescription = async (shopName: string, description: string): Promise<{ status: 'APPROVED' | 'REJECTED' | 'PENDING'; reason: string }> => {
    if (!process.env.API_KEY) return { status: 'APPROVED', reason: 'Dev Mode' };
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `Vendor: ${shopName}, Description: ${description}`,
            config: { 
                systemInstruction: "Audit vendor for authentic Bangladeshi fashion. Respond JSON: {status, reason}",
                responseMimeType: 'application/json' 
            }
        });
        return JSON.parse(response.text || '{}');
    } catch (error) {
        return { status: 'PENDING', reason: 'Audit failed.' };
    }
};

