  useEffect(() => {
    const initialProducts = getProducts();
    setAllProducts(initialProducts);
    setProducts(initialProducts);
    setVendors(getVendors());
    setSalesTicker(getLiveSales());

    const interval = setInterval(() => {
        setSalesTicker(prev => prev + Math.floor(Math.random() * 500));
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages, isTyping, isGeneratingImage]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    const intentPromise = analyzeSearchIntent(input);
    const responsePromise = generateAuraResponse(input);

    const [auraResponse, intent] = await Promise.all([responsePromise, intentPromise]);
    setIsTyping(false);

    let generatedImageUrl = undefined;
    if (intent?.shouldGenerateImage && intent.imagePrompt) {
        setIsGeneratingImage(true);
        const img = await generateAuraImage(intent.imagePrompt);
        generatedImageUrl = img || undefined;
        setIsGeneratingImage(false);
    }

    setMessages(prev => [...prev, { 
        role: 'ai', 
        content: auraResponse, 
        timestamp: Date.now(),
        generatedImageUrl 
    }]);

    if (intent && intent.isSearchQuery) {
        let filtered = [...allProducts, ...fictionalProducts];
        let hasFilter = false;

        if (intent.category) {
            filtered = filtered.filter(p => 
                p.category.toLowerCase().includes(intent.category!.toLowerCase()) || 
                p.name.toLowerCase().includes(intent.category!.toLowerCase())
            );
            hasFilter = true;
        }
        if (intent.color) {
            filtered = filtered.filter(p => 
                p.name.toLowerCase().includes(intent.color!.toLowerCase()) || 
                p.description.toLowerCase().includes(intent.color!.toLowerCase())
            );
            hasFilter = true;
        }
        if (intent.material) {
            filtered = filtered.filter(p => 
                p.description.toLowerCase().includes(intent.material!.toLowerCase()) ||
                p.name.toLowerCase().includes(intent.material!.toLowerCase())
            );
            hasFilter = true;
        }
        if (intent.style) {
            filtered = filtered.filter(p => 
                p.description.toLowerCase().includes(intent.style!.toLowerCase()) ||
                p.category.toLowerCase().includes(intent.style!.toLowerCase())
            );
            hasFilter = true;
        }
        if (intent.maxPrice) {
            filtered = filtered.filter(p => p.price <= intent.maxPrice!);
            hasFilter = true;
        }

        setProducts(filtered);
        setIsFiltered(hasFilter);

        if (hasFilter && filtered.length > 0) {
             const section = document.getElementById('product-section');
             section?.scrollIntoView({ behavior: 'smooth' });
        }
    }
  };

  const handleGenerateTrends = async () => {
    setIsGeneratingTrends(true);
    const trends = await generateTrendingProducts();
    const formattedTrends: Product[] = trends.map(t => ({
        ...t,
        vendorId: 0, // AI Vendor
        id: t.id + 1000 // Ensure unique ID
    }));

    setFictionalProducts(prev => [...prev, ...formattedTrends]);
    setProducts(prev => [...formattedTrends, ...prev]);
    setIsGeneratingTrends(false);

    setMessages(prev => [...prev, {
        role: 'ai',
        content: "আসসালামু আলাইকুম। আমি ২০২৬ সালের সম্ভাব্য ট্রেন্ড থেকে কিছু কাল্পনিক ডিজাইন তৈরি করেছি। আপনার গ্রিডের নিচে দেখুন!",
        timestamp: Date.now()
    }]);

    const section = document.getElementById('product-section');
    section?.scrollIntoView({ behavior: 'smooth' });
  };

  const clearChat = () => {
    setMessages([{ role: 'ai', content: "আসসালামু আলাইকুম। নতুন করে শুরু করি? আমি Aura, আপনার সেবায় নিয়োজিত।", timestamp: Date.now() }]);
  };

  return (
    <div className="min-h-screen">
      <section className="relative min-h-[600px] flex flex-col items-center justify-center px-6 py-20 overflow-hidden">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/10 blur-[120px] rounded-full pointer-events-none" />

        <div className="relative z-10 w-full max-w-4xl flex flex-col gap-10">
          <div className="text-center space-y-4">
             <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-aura-glassBorder bg-white/5 backdrop-blur-md">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-gray-300">
                   Ecosystem ভলিউম: ৳{salesTicker.toLocaleString()}
                </span>
             </div>
             <h1 className="text-4xl md:text-6xl font-serif font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white/60 leading-tight">
               SNEHALATA-স্নেহলতা
             </h1>
          </div>

          <div className="w-full bg-black/40 backdrop-blur-xl border border-white/10 rounded-3xl overflow-hidden shadow-2xl flex flex-col h-[500px]">
            <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5">
                <div className="flex items-center gap-2">
                    <Sparkles size={16} className="text-aura-purple" />
                    <span className="text-xs font-bold uppercase tracking-widest text-white">Aura Live Assistant</span>
                </div>
                <button onClick={clearChat} className="text-gray-500 hover:text-red-400 transition-colors">
                    <Trash2 size={16} />
                </button>
            </div>

            <div className="flex-1 p-6 overflow-y-auto space-y-6 scroll-smooth" ref={chatContainerRef}>
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl p-4 text-sm ${msg.role === 'user' ? 'bg-white text-black font-medium' : 'bg-white/10 text-gray-200 border border-white/5'}`}>
                    {msg.role === 'ai' && <div className="text-[10px] uppercase tracking-widest text-aura-purple mb-1 font-bold">Aura AI</div>}
                    <div className="whitespace-pre-wrap">{msg.content}</div>

                    {msg.generatedImageUrl && (
                        <div className="mt-4 rounded-xl overflow-hidden border border-white/10 shadow-lg">
                            <img src={msg.generatedImageUrl} alt="AI Concept" className="w-full h-auto" />
                            <div className="bg-black/40 backdrop-blur-md p-2 flex items-center gap-2 text-[10px] font-bold uppercase tracking-widest text-gray-400">
                                <ImageIcon size={12} /> Aura Conceptual Preview
                            </div>
                        </div>
                    )}

                    <div className="mt-2 text-[10px] flex items-center justify-end gap-1 opacity-50">
                        {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        <Clock size={10} />
                    </div>
                  </div>
                </div>
              ))}

              {isTyping && (
                <div className="flex justify-start">
                   <div className="bg-white/5 rounded-2xl p-4 flex gap-2">
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-75"></span>
                     <span className="w-2 h-2 bg-aura-purple rounded-full animate-bounce delay-150"></span>
                   </div>
                </div>
              )}

              {isGeneratingImage && (
                <div className="flex justify-start">
                   <div className="bg-white/5 rounded-2xl p-4 flex items-center gap-3">
                     <Loader2 size={16} className="text-aura-purple animate-spin" />
                     <span className="text-xs text-gray-400 font-bold uppercase tracking-widest">Aura is generating visual concepts...</span>
                   </div>
                </div>
              )}
            </div>

            <form onSubmit={handleSendMessage} className="p-4 bg-white/5 border-t border-white/10">
              <div className="flex gap-2">
                <div className="relative flex-1">
                    <input 
                    type="text" 
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="রঙ বা ডিজাইন বলুন (যেমন: 'লাল শাড়ি দেখাও')"
                    className="w-full bg-black/50 border border-white/10 rounded-xl pl-5 pr-12 py-4 focus:outline-none focus:border-aura-purple text-sm"
                    />
                    <button type="submit" className="absolute right-2 top-2 p-2 bg-aura-purple rounded-lg text-white">
                    <Send size={18} />
                    </button>
                </div>
                <button 
                    type="button" 
                    onClick={handleGenerateTrends}
                    disabled={isGeneratingTrends}
                    className="bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl px-4 py-2 text-white flex items-center gap-2 transition-all disabled:opacity-50"
                    title="Generate AI Trends"
                >
                    {isGeneratingTrends ? (
                        <Loader2 size={18} className="animate-spin text-aura-purple" />
                    ) : (
                        <Wand2 size={18} className="text-aura-purple" />
                    )}
                    <span className="hidden md:inline text-xs font-bold uppercase tracking-widest">Trends</span>
                </button>
              </div>
            </form>
          </div>
        </div>
      </section>

      <section id="product-section" className="max-w-7xl mx-auto px-6 py-10">
        <div className="flex items-center justify-between mb-10">
            <h2 className="text-2xl font-serif font-bold flex items-center gap-4">
                <Sparkles className="text-aura-purple" />
                {isFiltered ? 'AI ফিল্টার করা পণ্য' : ' ট্রেন্ডিং কালেকশন'}
            </h2>
            {isFiltered && (
                <button onClick={() => { setProducts(allProducts.concat(fictionalProducts)); setIsFiltered(false); }} className="flex items-center gap-2 px-4 py-2 bg-white/10 rounded-full text-xs font-bold uppercase tracking-widest transition-colors hover:bg-white/20">
                    <X size={14} /> Clear
                </button>
            )}
        </div>

        {products.length === 0 ? (
            <div className="text-center py-20 bg-white/5 border border-dashed border-white/10 rounded-3xl">
                <Filter className="mx-auto text-gray-600 mb-4" size={40} />
                <h3 className="text-xl font-bold text-gray-400">কোনো পণ্য পাওয়া যায়নি</h3>
            </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {products.map(p => (
                    <div key={p.id} className="relative">
                        {p.vendorId === 0 && (
                            <div className="absolute -top-3 -right-3 z-20 bg-aura-purple text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg flex items-center gap-1">
                                <Sparkles size={10} /> AI Concept
                            </div>
                        )}
                        <ProductCard 
                            product={p} 
                            vendor={p.vendorId === 0 ? { id: 0, name: "Aura Innovations", slug: "aura", status: "APPROVED", description: "AI Generated Concepts" } : vendors.find(v => v.id === p.vendorId)} 
                        />
                    </div>
                ))}
            </div>
        )}
      </section>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
