  const [status, setStatus] = useState<'IDLE' | 'AUDITING' | 'SAVING' | 'SUCCESS' | 'REJECTED'>('IDLE');
  const [auditResult, setAuditResult] = useState<{ status: string; reason: string } | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus('AUDITING');

    const audit = await auditVendorDescription(formData.shopName, formData.description);
    setAuditResult(audit);

    if (audit.status === 'REJECTED') {
        setStatus('REJECTED');
        return;
    }

    setStatus('SAVING');
    const { error } = await submitVendorRequest({
        name: formData.shopName,
        description: formData.description,
        owner: formData.ownerName,
        contact: formData.contact,
        status: 'APPROVED', 
        joined_at: new Date().toISOString()
    });

    if (error) {
        console.error(error);
        alert("Database connection failed. Please check console.");
        setStatus('IDLE');
    } else {
        setStatus('SUCCESS');
