        contents: `Analyze: "${userPrompt}". Extract category, maxPrice, material (e.g., cotton, silk), color (e.g., red, blue, black), style (e.g., vintage, modern, traditional), and semanticKeywords.`,
        config: { 
          responseMimeType: 'application/json',
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              category: { type: Type.STRING },
              maxPrice: { type: Type.NUMBER },
              material: { type: Type.STRING },
              color: { type: Type.STRING },
              style: { type: Type.STRING },
              semanticKeywords: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          }
        }
    });
    try {
        return JSON.parse(response.text || 'null');
    } catch (e) {
        return null;
    }
};

