        className={`w-16 h-16 rounded-2xl flex items-center justify-center shadow-2xl transition-all duration-500 group relative overflow-hidden ${
          isOpen ? 'bg-white text-black rotate-90 scale-90' : 'bg-aura-purple text-white hover:scale-110 active:scale-95'
        }`}
