                <Sparkles className="absolute inset-0 m-auto text-white animate-pulse" size={16} />
              </div>
              <p className="text-[10px] font-black uppercase tracking-[0.3em] text-white">Aura Refinement Active</p>
            </div>
          )}

          {/* Quick Action Floating Overlay */}
          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-all duration-500 backdrop-blur-[1px] flex flex-col items-center justify-center gap-6 p-6">
            <div className="flex gap-4 translate-y-4 group-hover:translate-y-0 transition-all duration-500">
              <button 
                onClick={handleQuickAdd}
                className={`p-5 rounded-2xl transition-all shadow-2xl active:scale-90 ${
                  isQuickAdded 
                    ? 'bg-green-500 text-white shadow-[0_0_20px_rgba(34,197,94,0.4)]' 
                    : 'bg-white text-black hover:bg-aura-purple hover:text-white'
                }`}
                title="Quick Add to Bag"
              >
                {isQuickAdded ? <CheckCircle2 size={22} className="animate-bounce" /> : <ShoppingCart size={22} />}
              </button>

              <button 
                onClick={handleShare}
                className="bg-white/10 backdrop-blur-md text-white p-5 rounded-2xl hover:bg-aura-purple hover:text-white transition-all border border-white/10 active:scale-90"
                title="Share Product"
              >
                 <Share2 size={22} />
              </button>

              <Link 
                to={`/store/${vendor?.slug || ''}`}
                className="bg-white/10 backdrop-blur-md text-white p-5 rounded-2xl hover:bg-white hover:text-black transition-all border border-white/10 active:scale-90"
                title="Visit Store"
              >
                <Eye size={22} />
              </Link>
            </div>

            <button 
              onClick={() => setIsModalOpen(true)}
              className="w-full bg-white text-black py-5 rounded-2xl text-[11px] font-black uppercase tracking-[0.3em] shadow-2xl translate-y-8 group-hover:translate-y-0 transition-all opacity-0 group-hover:opacity-100 delay-100 hover:bg-aura-purple hover:text-white"
            >
              Order Now
            </button>
          </div>

          {/* Top Actions: Try On and Refine */}
          <div className="absolute top-4 left-4 right-4 flex justify-between items-center z-20">
            <button 
              onClick={() => setIsRefineModalOpen(true)}
              className="bg-black/60 backdrop-blur-md text-white p-3 rounded-2xl border border-white/10 hover:bg-aura-purple hover:border-aura-purple/50 transition-all active:scale-95 shadow-lg group/btn"
              title="Advanced Style Options"
            >
              <Palette size={18} className="group-hover/btn:rotate-12 transition-transform" />
            </button>

            <Link 
              to={`/try-on/${product.id}`}
              className="bg-aura-purple text-white px-5 py-3 rounded-2xl flex items-center gap-2 text-[10px] font-black uppercase tracking-widest shadow-[0_10px_30px_rgba(124,58,237,0.4)] border border-white/20 hover:scale-105 active:scale-95 transition-all"
            >
              <Shirt size={16} /> Try On
            </Link>
          </div>

          {/* Neural Vision Badge */}
          <div className="absolute bottom-4 left-4 flex items-center gap-2 bg-black/60 backdrop-blur-md px-4 py-2 rounded-full border border-white/10 z-20">
            <Sparkles size={12} className="text-aura-purple animate-pulse" />
            <span className="text-[9px] font-black uppercase tracking-widest text-white/90">Aura Vision Ready</span>
          </div>
        </div>

        {/* Inline Style Presets */}
        <div className="px-1 overflow-x-auto pb-2 scrollbar-hide">
          <div className="flex gap-2 w-max">
             <div className="flex items-center gap-2 pr-2 border-r border-white/10 mr-2">
               <Wand2 size={12} className="text-aura-purple" />
               <span className="text-[9px] font-black uppercase tracking-widest text-gray-500">Quick FX</span>
             </div>
             {STYLE_PRESETS.map((preset) => (
