export const Home: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [filteredProducts, setFilteredProducts] = useState<Product[]>([]);
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [stats, setStats] = useState<EcosystemStats | null>(null);

  // Search State
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearching, setIsSearching] = useState(false);
  const [activeIntent, setActiveIntent] = useState<SearchIntent | null>(null);

  useEffect(() => {
    const allProducts = getProducts();
    setProducts(allProducts);
    setFilteredProducts(allProducts);
    setVendors(getVendors());
    setStats(getEcosystemStats());
  }, []);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) {
        setFilteredProducts(products);
        setActiveIntent(null);
        return;
    }

    setIsSearching(true);
    setActiveIntent(null);

    try {
        const intent = await analyzeSearchIntent(searchQuery);
        setActiveIntent(intent);

        if (intent) {
            const filtered = products.filter(p => {
                // Category Match
                const matchCat = intent.category 
                    ? p.category.toLowerCase().includes(intent.category.toLowerCase()) 
                    : true;

                // Price Match
                const matchPrice = intent.maxPrice 
                    ? p.price <= intent.maxPrice 
                    : true;

                // Material Match (Description or Name)
                const matchMaterial = intent.material 
                    ? (p.description.toLowerCase().includes(intent.material.toLowerCase()) || p.name.toLowerCase().includes(intent.material.toLowerCase()))
                    : true;

                // Color Match (Description or Name)
                const matchColor = intent.color
                    ? (p.description.toLowerCase().includes(intent.color.toLowerCase()) || p.name.toLowerCase().includes(intent.color.toLowerCase()))
                    : true;

                // Style Match (Description or Name or Category)
                const matchStyle = intent.style
                    ? (p.description.toLowerCase().includes(intent.style.toLowerCase()) || p.name.toLowerCase().includes(intent.style.toLowerCase()) || p.category.toLowerCase().includes(intent.style.toLowerCase()))
                    : true;

                return matchCat && matchPrice && matchMaterial && matchColor && matchStyle;
            });
            setFilteredProducts(filtered);
        } else {
            // Fallback simple search
            const lower = searchQuery.toLowerCase();
            setFilteredProducts(products.filter(p => p.name.toLowerCase().includes(lower) || p.description.toLowerCase().includes(lower)));
        }
    } catch (err) {
        console.error(err);
        // Simple fallback on error
        const lower = searchQuery.toLowerCase();
        setFilteredProducts(products.filter(p => p.name.toLowerCase().includes(lower) || p.description.toLowerCase().includes(lower)));
    } finally {
        setIsSearching(false);
    }
  };

  const clearSearch = () => {
      setSearchQuery('');
      setFilteredProducts(products);
      setActiveIntent(null);
  };

  return (
    <div className="min-h-screen bg-black">
      {/* Neural Link Header Status */}
      <div className="bg-aura-purple/5 border-b border-white/5 py-3 overflow-hidden">
        <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
              <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse shadow-[0_0_10px_#22c55e]"></span>
              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-green-400">Neural Link Active</span>
            </div>
            <div className="hidden md:flex items-center gap-2 text-[10px] text-gray-600 font-bold uppercase tracking-widest">
              <Terminal size={12} /> SYNC_LATENCY: 14ms
            </div>
          </div>
          <div className="text-[10px] text-aura-purple/80 font-black uppercase tracking-widest flex items-center gap-2">
            Aura Neural Hub • Gemini 3.0 Pro <Sparkles size={12} className="animate-pulse" />
          </div>
        </div>
      </div>

      {/* Hero Section - Brand Focus */}
      <section className="relative pt-32 pb-40 px-6 overflow-hidden min-h-[80vh] flex flex-col items-center justify-center">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-full pointer-events-none overflow-hidden">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-aura-purple/10 blur-[150px] rounded-full opacity-50" />
        </div>

        <div className="max-w-7xl mx-auto text-center relative z-10 w-full">

             {/* Massive Brand Name */}
             <div className="flex flex-col items-center gap-0 mb-16 select-none animate-in zoom-in duration-1000">
                <h2 className="text-3xl md:text-5xl lg:text-7xl text-white/90 font-black uppercase tracking-[0.3em] md:tracking-[0.6em] pl-4 md:pl-12 mb-[-0.5rem] md:mb-[-1.5rem] z-10 drop-shadow-2xl">
                  SNEHALATA
                </h2>
                <h1 className="text-[5rem] md:text-[8rem] lg:text-[10rem] font-black text-white leading-none tracking-tighter bn-heavy drop-shadow-[0_0_80px_rgba(124,58,237,0.4)] bg-clip-text text-transparent bg-gradient-to-b from-white via-white to-gray-500">
                  স্নেহলতা
                </h1>
             </div>

             {/* Embedded Aura AI Chat (Replaces Text Greeting) */}
             <div className="w-full px-4 mb-20 animate-in fade-in slide-in-from-bottom-8 duration-1000 delay-300">
                <ChatAssistant embedded={true} className="shadow-[0_0_100px_rgba(124,58,237,0.2)]" />
             </div>

             <div className="flex flex-wrap justify-center gap-6 animate-in fade-in slide-in-from-bottom-8 duration-1000 delay-500">
                <Link to="/studio" className="group relative bg-white text-black px-12 py-6 rounded-2xl font-black uppercase tracking-[0.2em] text-[11px] flex items-center gap-3 transition-all hover:scale-105 active:scale-95 shadow-[0_20px_40px_rgba(255,255,255,0.1)] overflow-hidden">
                  <div className="absolute inset-0 bg-aura-purple/10 translate-y-full group-hover:translate-y-0 transition-transform" />
                  <Sparkles size={18} className="relative z-10" /> <span className="relative z-10">জেনারেট ইমেজ/ভিডিও</span>
                </Link>
                <Link to="/studio" className="bg-white/5 border border-white/10 text-white px-12 py-6 rounded-2xl font-black uppercase tracking-[0.2em] text-[11px] flex items-center gap-3 hover:bg-white/10 transition-all active:scale-95 backdrop-blur-md">
                  <MessageSquare size={18} /> Aura AI চ্যাট
                </Link>
             </div>
        </div>
      </section>

      {/* Hub Catalog Section */}
      <section className="max-w-7xl mx-auto px-6 py-20 border-t border-white/5">
        <div className="flex flex-col md:flex-row items-end justify-between mb-16 gap-12">
          <div className="space-y-4">
            <h2 className="text-5xl font-serif font-black text-white leading-tight">ইকোসিস্টেম ক্যাটালগ</h2>
            <p className="text-[11px] text-gray-500 uppercase tracking-[0.5em] font-black flex items-center gap-3">
              <span className="w-12 h-px bg-aura-purple/40"></span>
              Exclusive direct-from-artisan collection
            </p>
          </div>

          {/* AI Search Bar */}
          <div className="w-full md:w-auto flex-1 max-w-xl">
             <form onSubmit={handleSearch} className="relative group">
                <div className="absolute inset-0 bg-gradient-to-r from-aura-purple/20 to-blue-500/20 rounded-2xl blur-lg opacity-0 group-hover:opacity-100 transition-opacity"></div>
                <div className="relative bg-white/5 border border-white/10 rounded-2xl flex items-center p-2 focus-within:border-aura-purple/50 transition-all backdrop-blur-xl">
                    <Search className="text-gray-500 ml-4 shrink-0" size={20} />
                    <input 
                        type="text"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder="Search by material (e.g. Silk, Cotton)..."
                        className="w-full bg-transparent border-none text-white px-4 py-3 focus:outline-none placeholder-gray-600 font-medium"
                    />
                    {searchQuery && (
                        <button type="button" onClick={clearSearch} className="p-2 text-gray-500 hover:text-white transition-colors"><X size={16}/></button>
                    )}
                    <button 
                        type="submit"
                        disabled={isSearching}
                        className="bg-white text-black px-6 py-3 rounded-xl font-bold uppercase tracking-widest text-[10px] hover:bg-aura-purple hover:text-white transition-all shadow-lg flex items-center gap-2 shrink-0"
                    >
                        {isSearching ? <Loader2 size={14} className="animate-spin" /> : <Sparkles size={14} />}
                        Search
                    </button>
                </div>
             </form>
          </div>
        </div>

        {/* Active AI Filters */}
        {activeIntent && (
            <div className="flex flex-wrap gap-3 mb-10 animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-2 text-[10px] uppercase tracking-widest font-black text-gray-500 mr-2">
                    <Filter size={12} /> Active Filters:
                </div>
                {activeIntent.material && (
                    <span className="px-4 py-1.5 rounded-full bg-purple-500/10 border border-purple-500/20 text-purple-400 text-xs font-bold flex items-center gap-2">
                        Material: {activeIntent.material}
                    </span>
                )}
                {activeIntent.category && (
                    <span className="px-4 py-1.5 rounded-full bg-blue-500/10 border border-blue-500/20 text-blue-400 text-xs font-bold flex items-center gap-2">
                        Category: {activeIntent.category}
                    </span>
                )}
                {activeIntent.maxPrice && (
                    <span className="px-4 py-1.5 rounded-full bg-green-500/10 border border-green-500/20 text-green-400 text-xs font-bold flex items-center gap-2">
                        Max Price: ৳{activeIntent.maxPrice}
                    </span>
                )}
                {activeIntent.color && (
                    <span className="px-4 py-1.5 rounded-full bg-pink-500/10 border border-pink-500/20 text-pink-400 text-xs font-bold flex items-center gap-2">
                        Color: {activeIntent.color}
                    </span>
                )}
                {activeIntent.style && (
                    <span className="px-4 py-1.5 rounded-full bg-yellow-500/10 border border-yellow-500/20 text-yellow-400 text-xs font-bold flex items-center gap-2">
                        Style: {activeIntent.style}
                    </span>
                )}
            </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-16">
          {filteredProducts.length > 0 ? (
             filteredProducts.map(p => (
               <ProductCard key={p.id} product={p} vendor={vendors.find(v => v.id === p.vendorId)} />
             ))
          ) : (
             <div className="col-span-full text-center py-20 opacity-50">
                <ShoppingBag size={48} className="mx-auto mb-4" />
                <p className="text-xl font-serif">No items found matching your criteria.</p>
                <button onClick={clearSearch} className="text-aura-purple mt-4 hover:underline">Clear Filters</button>
             </div>
          )}
        </div>

        {filteredProducts.length > 0 && (
            <div className="mt-24 text-center">
              <button className="inline-flex items-center gap-3 text-[11px] font-black uppercase tracking-[0.4em] text-gray-500 hover:text-aura-purple transition-all group">
                Explore All Creations <ArrowRight size={18} className="group-hover:translate-x-2 transition-transform" />
              </button>
            </div>
        )}
      </section>

      {/* Pulse Stats Hub (Moved Here) */}
      <section className="max-w-7xl mx-auto px-6 py-20 relative z-20 border-t border-white/5 bg-white/[0.02]">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <StatCard icon={<Cpu className="text-aura-purple" />} label="Artisan Nodes" value={stats?.totalVendors || '0'} sub="Verified Ecosystem" />
          <StatCard icon={<ShoppingBag className="text-blue-400" />} label="Live Items" value={stats?.activeProducts || '0'} sub="Audited Inventory" />
          <StatCard icon={<Activity className="text-green-400" />} label="Neural Pulse" value="Optimal" sub="System Synced" />
          <StatCard icon={<ShieldCheck className="text-amber-400" />} label="Security" value="Active" sub="Neural Shield v3.1" />
        </div>
      </section>

    </div>
  );
};

const StatCard = ({ icon, label, value, sub }: any) => (
  <div className="bg-aura-glass border border-aura-glassBorder rounded-[2.5rem] p-8 backdrop-blur-3xl shadow-2xl hover:border-aura-purple/50 transition-all duration-500 group relative overflow-hidden">
    <div className="absolute top-0 right-0 w-24 h-24 bg-aura-purple/5 blur-[40px] rounded-full pointer-events-none group-hover:bg-aura-purple/10 transition-all" />
    <div className="p-4 bg-white/5 rounded-2xl w-fit mb-6 group-hover:bg-aura-purple group-hover:text-white transition-all shadow-xl">{icon}</div>
    <div className="text-4xl font-black text-white mb-2 tracking-tighter tabular-nums">{value}</div>
    <div className="text-[10px] uppercase tracking-[0.3em] font-black text-gray-400 mb-1">{label}</div>
    <div className="text-[9px] text-gray-600 font-bold uppercase tracking-widest">{sub}</div>
  </div>
);

import React, { useState, useEffect, useRef } from 'react';
import { MessageSquare, X, Send, Sparkles, Bot, User, Loader2, Cpu, Download, Image as ImageIcon, Trash2, MoreHorizontal, ArrowUp } from 'lucide-react';
import { startAuraChat, generateAuraImage, generateAuraResponse } from '../services/geminiService';
import { ChatMessage } from '../types';
import { useLocation } from './Navigation';

interface ChatAssistantProps {
  embedded?: boolean;
  className?: string;
}

export const ChatAssistant: React.FC<ChatAssistantProps> = ({ embedded = false, className = '' }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const chatRef = useRef<any>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const { path } = useLocation();

  useEffect(() => {
    // Initialize welcome message
    if ((isOpen || embedded) && messages.length === 0) {
      setMessages([{
        role: 'ai',
        content: 'আসসালামু আলাইকুম! আমি Aura AI। আমি আপনার জন্য তথ্য দিতে পারি অথবা আপনার কল্পনা অনুযায়ী চমৎকার ছবি তৈরি করে দিতে পারি। আমি আপনাকে কীভাবে সাহায্য করতে পারি?',
        timestamp: Date.now()
      }]);
    }
  }, [isOpen, embedded]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping, isGeneratingImage]);

  const handleClearChat = () => {
    setMessages([{
        role: 'ai',
        content: 'চ্যাট ইতিহাস মুছে ফেলা হয়েছে। আমি আপনাকে কীভাবে সাহায্য করতে পারি?',
        timestamp: Date.now()
    }]);
    // Reset the chat session to clear backend context/history
    chatRef.current = null;
  };

  const isImageRequest = (text: string) => {
    const keywords = ['image', 'picture', 'photo', 'drawing', 'ছবি', 'পিকচার', 'আঁকো', 'তৈরি করো', 'create', 'generate'];
    return keywords.some(k => text.toLowerCase().includes(k));
  };

  const formatTime = (timestamp: number) => {
    return new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping || isGeneratingImage) return;

    const userMsg: ChatMessage = {
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    const currentInput = input;
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      // Check for image generation intent
      if (isImageRequest(currentInput)) {
        setIsGeneratingImage(true);
        const imageUrl = await generateAuraImage(currentInput);

        if (imageUrl) {
          const aiImgMsg: ChatMessage = {
            role: 'ai',
            content: `আপনার অনুরোধ অনুযায়ী আমি এই ছবিটি তৈরি করেছি: "${currentInput}"`,
            generatedImageUrl: imageUrl,
            timestamp: Date.now()
          };
          setMessages(prev => [...prev, aiImgMsg]);
          setIsGeneratingImage(false);
          setIsTyping(false);
          return;
        }
      }

      // Initialize chat session if not already active or cleared
      if (!chatRef.current) {
        chatRef.current = startAuraChat();
      }

      // Use the resilient generateAuraResponse function
      const responseText = await generateAuraResponse(chatRef.current, currentInput);

      const aiMsg: ChatMessage = {
        role: 'ai',
        content: responseText,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      setMessages(prev => [...prev, {
        role: 'ai',
        content: 'একটি টেকনিক্যাল সমস্যা হয়েছে। দয়া করে কিছুক্ষণ পর আবার চেষ্টা করুন।',
        timestamp: Date.now()
      }]);
    } finally {
      setIsTyping(false);
      setIsGeneratingImage(false);
    }
  };

  // Logic to hide the floating button on the Home page where the embedded chat exists
  const isFloatingHidden = !embedded && path === '/';

  const wrapperClass = embedded 
    ? `relative w-full max-w-4xl mx-auto z-20 font-sans my-10 ${className}` 
    : `fixed bottom-8 right-8 z-[150] font-sans ${isFloatingHidden ? 'hidden' : ''}`;

  const windowClass = embedded
    ? "w-full h-[600px] bg-aura-glass border border-aura-glassBorder rounded-[2.5rem] shadow-[0_0_80px_rgba(124,58,237,0.15)] backdrop-blur-3xl flex flex-col overflow-hidden animate-in fade-in zoom-in duration-700"
    : "absolute bottom-20 right-0 w-[400px] max-w-[calc(100vw-2rem)] h-[600px] max-h-[calc(100vh-10rem)] bg-aura-glass border border-aura-glassBorder rounded-[2.5rem] shadow-2xl backdrop-blur-3xl flex flex-col overflow-hidden animate-in slide-in-from-bottom-10 fade-in duration-500";

  return (
    <div className={wrapperClass}>
      {/* Floating Toggle Button (Only if not embedded) */}
      {!embedded && (
        <button
          onClick={() => setIsOpen(!isOpen)}
          className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all duration-500 group relative overflow-hidden ${
            isOpen ? 'bg-white text-black rotate-90 scale-90' : 'bg-aura-purple text-white hover:scale-110 active:scale-95'
          }`}
        >
          <div className="absolute inset-0 bg-gradient-to-tr from-white/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
          {isOpen ? <X size={24} /> : <MessageSquare size={24} />}
          {!isOpen && (
            <div className="absolute -top-0.5 -right-0.5 w-3.5 h-3.5 bg-red-500 rounded-full border-2 border-black animate-pulse" />
          )}
        </button>
      )}

      {/* Chat Window */}
      {(isOpen || embedded) && (
        <div className={windowClass}>
          {/* Header */}
          <header className="p-5 bg-white/5 border-b border-white/5 flex items-center justify-between relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-full bg-aura-purple/5 blur-[40px] pointer-events-none" />
            <div className="flex items-center gap-3 relative z-10">
              <div className="w-9 h-9 bg-aura-purple/20 rounded-xl flex items-center justify-center border border-aura-purple/30 shadow-[0_0_10px_rgba(124,58,237,0.2)]">
                <Cpu className="text-aura-purple animate-pulse" size={18} />
              </div>
              <div>
                <h3 className="text-white font-bold text-xs tracking-widest flex items-center gap-2">
                  AURA INTELLIGENCE <Sparkles size={10} className="text-aura-purple" />
                </h3>
                <p className="text-[8px] uppercase tracking-[0.2em] font-black flex items-center gap-2 mt-0.5">
                    {isTyping ? (
                        <span className="text-aura-purple animate-pulse">Thinking...</span>
                    ) : (
                        <span className="text-green-400 flex items-center gap-1"><span className="w-1 h-1 rounded-full bg-green-400"></span> Online</span>
                    )}
                </p>
              </div>
            </div>

            {/* Actions */}
            <div className="relative z-10">
                <button 
                    onClick={handleClearChat}
                    className="p-2 text-gray-500 hover:text-red-400 hover:bg-white/5 rounded-full transition-all group"
                    title="Clear Chat History"
                >
                    <Trash2 size={16} className="group-hover:scale-110 transition-transform" />
                </button>
            </div>
          </header>

          {/* Messages Area */}
          <div className="flex-1 overflow-y-auto p-5 space-y-5 scrollbar-hide">
            {messages.map((msg, idx) => (
              <div
                key={idx}
                className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}
              >
                <div className={`flex gap-2.5 max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                  <div className={`w-7 h-7 rounded-lg shrink-0 flex items-center justify-center border ${
                    msg.role === 'user' ? 'bg-white/10 border-white/10' : 'bg-aura-purple/20 border-aura-purple/30'
                  }`}>
                    {msg.role === 'user' ? <User size={12} className="text-gray-400" /> : <Bot size={12} className="text-aura-purple" />}
                  </div>
                  <div className="space-y-1">
                    <div className={`px-4 py-3 rounded-2xl text-xs leading-relaxed shadow-sm ${
                      msg.role === 'user' 
                      ? 'bg-white text-black font-medium rounded-tr-none' 
                      : 'bg-white/5 text-gray-200 border border-white/5 rounded-tl-none'
                    }`}>
                      {msg.content}
                    </div>
                    {msg.generatedImageUrl && (
                      <div className="relative group rounded-2xl overflow-hidden border border-white/10 bg-black/40 animate-in zoom-in duration-700 mt-2">
                        <img src={msg.generatedImageUrl} className="w-full h-auto object-cover" alt="AI Generated" />
                        <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                           <a 
                             href={msg.generatedImageUrl} 
                             download="aura-ai-art.png"
                             className="p-2.5 bg-white text-black rounded-xl hover:bg-aura-purple hover:text-white transition-all shadow-2xl"
                           >
                             <Download size={14} />
                           </a>
                        </div>
                      </div>
                    )}
                    <span className={`text-[8px] text-gray-600 block ${msg.role === 'user' ? 'text-right' : 'text-left'} px-1`}>
                        {formatTime(msg.timestamp)}
                    </span>
                  </div>
                </div>
              </div>
            ))}

            {/* AI Typing Indicator Bubble */}
            {(isTyping || isGeneratingImage) && (
              <div className="flex justify-start animate-in fade-in slide-in-from-bottom-2">
                 <div className="flex gap-2.5 max-w-[90%]">
                    <div className="w-7 h-7 rounded-lg shrink-0 flex items-center justify-center border bg-aura-purple/20 border-aura-purple/30">
                        <Bot size={12} className="text-aura-purple" />
                    </div>
                    <div className="bg-white/5 border border-white/5 px-4 py-3 rounded-2xl rounded-tl-none flex items-center gap-3">
                        {isGeneratingImage ? (
                            <>
                                <ImageIcon size={12} className="text-aura-purple animate-bounce" />
                                <span className="text-[9px] text-gray-400 font-bold uppercase tracking-widest animate-pulse">Rendering...</span>
                            </>
