                setError("ইকোসিস্টেমের ছবি অ্যাক্সেস করতে সমস্যা হচ্ছে। দয়া করে আপনার ডিভাইসে ছবিটি ডাউনলোড করে আপলোড করুন।");
                setIsProcessing(false);
                return;
            }
