const loadFromDB = <T>(key: string): T[] => {
    try {
        const item = localStorage.getItem(key);
        return item ? JSON.parse(item) : [];
    } catch {
        return [];
    }
};

const saveToDB = (key: string, data: any[]) => {
    localStorage.setItem(key, JSON.stringify(data));
};

